exercise.solution:
/* TODO 1: Style all paragraphs */
p {
  line-height: 1.7;
  color: #333;
}

/* TODO 2: Style elements with class 'badge' */
.badge {
  display: inline-block;
  background-color: #4f46e5;
  color: white;
  font-size: 0.75rem;
  font-weight: 600;
  padding: 3px 10px;
  border-radius: 999px;
  letter-spacing: 0.04em;
  text-transform: uppercase;
}

/* TODO 3: Style the element with id 'page-title' */
#page-title {
  font-size: 2.5rem;
  color: #1a1a2e;
}

/* TODO 4: Add a :hover state to .badge */
.badge:hover {
  background-color: #4338ca;
}
